const html = $input.first().json.data;

// Extract all script blocks
const matches = [...html.matchAll(/AF_initDataCallback\((\{[\s\S]*?\})\);/g)];

let reviews = [];

for (const match of matches) {
  try {
    const parsed = JSON.parse(match[1]);

    if (parsed.key !== 'ds:11') continue;

    // 🔥 FIX: Correct nesting level
    const reviewBlocks = parsed?.data?.[0]?.[0] || [];

    if (!Array.isArray(reviewBlocks)) continue;

    for (const r of reviewBlocks) {
      try {
        const review_id = r?.[0];
        const author = r?.[1]?.[0] || "Anonymous";
        const rating = r?.[2] || r?.[1]?.[1]?.[1] || 3;
        const body = r?.[4] || "";

        const timestampSec = r?.[5]?.[0];
        const date = timestampSec
          ? new Date(timestampSec * 1000).toISOString()
          : new Date().toISOString();

        if (!body) continue;

        reviews.push({
          review_id,
          author,
          rating,
          body,
          date
        });

      } catch {}
    }

  } catch {}
}

// 🚨 DEBUG: if still empty, return raw structure
if (reviews.length === 0) {
  return [{
    json: {
      error: "No reviews parsed",
      hint: "Structure may have changed",
      sample_keys: matches.map(m => {
        try {
          const p = JSON.parse(m[1]);
          return p.key;
        } catch { return null; }
      }).filter(Boolean)
    }
  }];
}

// Final output
return reviews.slice(0, 20).map((r, i) => ({
  json: {
    review_id:      r.review_id || `playstore_${Date.now()}_${i}`,
    platform:       'google_play',
    author:         r.author,
    rating:         r.rating,
    title:          '',
    body:           r.body,
    body_truncated: r.body.slice(0, 500),
    date:           r.date,
    url:            'https://play.google.com/store/apps/details?id=YOUR.APP',
    fetched_at:     new Date().toISOString()
  }
}));

const feed = $input.first().json.feed;
const entries = feed?.entry || [];

// Skip first entry — it's the app metadata, not a review
return entries.slice(1).map(r => ({
  json: {
    review_id:      `appstore_${r.id?.label || Math.random()}`,
    platform:       'app_store',
    author:         r.author?.name?.label || 'Anonymous',
    rating:         parseInt(r['im:rating']?.label) || 3,
    title:          r.title?.label || '',
    body:           r.content?.label || '',
    body_truncated: (r.content?.label || '').slice(0, 500),
    date:           r.updated?.label || new Date().toISOString(),
    url:            `https://apps.apple.com/app/id${r['im:appId']?.label}`,
    fetched_at:     new Date().toISOString()
  }
}));

const stripHtml = s => (s || '').replace(/<[^>]*>/g, '').replace(/\s+/g, ' ').trim();

return $input.all().map(item => {
  const r = item.json;
  const body = stripHtml(r.body || r.body_truncated || '');
  return {
    json: {
      review_id:      r.review_id || `unknown_${Date.now()}`,
      platform:       r.platform || 'unknown',
      author:         stripHtml(r.author),
      rating:         Math.min(5, Math.max(1, parseInt(r.rating) || 3)),
      title:          stripHtml(r.title).slice(0, 200),
      body:           body,
      body_truncated: body.slice(0, 500),
      date:           r.date || new Date().toISOString(),
      url:            r.url || '',
      fetched_at:     new Date().toISOString(),
      // AI fields — to be filled by Node 14
      sentiment:      null,
      urgency:        null,
      tags:           [],
      ai_response:    null,
      processed:      false
    }
  };
});

return $input.all().map(item => {
  const raw = item.json.choices?.[0]?.message?.content || '{}';

  let aiData = {};
  try {
    // Strip markdown code fences if model wraps in ```json```
    const clean = raw.replace(/```json|```/g, '').trim();
    aiData = JSON.parse(clean);
  } catch(e) {
    // Fallback: extract fields with regex if JSON is malformed
    aiData = {
      sentiment: (raw.match(/"sentiment"\s*:\s*"(\w+)"/) || [])[1] || 'neutral',
      rating:    parseInt((raw.match(/"rating"\s*:\s*(\d)/) || [])[1]) || 3,
      urgency:   (raw.match(/"urgency"\s*:\s*"(\w+)"/) || [])[1] || 'low',
      tags:      [],
      response:  ''
    };
  }

  return {
    json: {
      ...item.json,          // pass through all original review fields
      sentiment:    aiData.sentiment || 'neutral',
      ai_rating:    aiData.rating || 3,
      urgency:      aiData.urgency || 'low',
      tags:         aiData.tags || [],
      ai_response:  aiData.response || '',
      processed:    true,
      processed_at: new Date().toISOString()
    }
  };
});

